const FILE_RULES = {
  'models.py': 'Pydantic v2 data models only. No routes, no FastAPI app, no business logic. Only class definitions and type imports.',
  'routes.py': 'FastAPI APIRouter with all endpoint implementations. Import models from models.py. Include in-memory store at module level. All business logic goes here.',
  'main.py': 'FastAPI app instantiation only. Import the router from routes.py and include it. Keep this file minimal — no business logic.',
  'test_main.py': 'pytest + httpx async tests. Import app from main. Test every acceptance criterion from the PRD. Use AsyncClient(transport=ASGITransport(app=app), base_url="http://test").'
};

const DEFAULT_FILES = ['models.py', 'routes.py', 'main.py', 'test_main.py'];

const body = $input.first().json.body || $input.first().json;
const spec = body.spec || '';
const filename = body.filename || '';
const allFiles = body.all_files || DEFAULT_FILES;
const context = body.context || [];  // [{filename, content}, ...] of already-generated files

if (!spec) throw new Error('Missing required field: spec');
if (!filename) throw new Error('Missing required field: filename');

const fileHint = FILE_RULES[filename] || `Implement the ${filename} component based on the PRD.`;
const otherFiles = allFiles.filter(f => f !== filename);

// Build context block from previously generated files
const contextBlock = context.length > 0
  ? `\n\nALREADY GENERATED FILES — you MUST use the exact same class names, field names, function names, and import paths as these files:\n\n${context.map(f => `--- ${f.filename} ---\n${f.content}`).join('\n\n')}`
  : '';

const systemPrompt = `You are a senior software engineer implementing one specific file from a PRD.

You will generate ONLY the file: ${filename}
Do not generate any other files. Do not add explanations or markdown fences.

This file's responsibility: ${fileHint}

Other files in this project (already handled separately, do not duplicate their content):
${otherFiles.map(f => `- ${f}: ${FILE_RULES[f] || f}`).join('\n')}${contextBlock}

Rules:
- Use FastAPI for HTTP endpoints
- Use Pydantic v2: import directly with 'from pydantic import BaseModel, Field' (never from pydantic.v1 or pydantic.v2)
- Store monetary values as INTEGER cents to avoid floating-point errors
- Return amounts as decimal strings (e.g., "90.00") using format(amount_cents / 100, '.2f')
- Include error handling for 404 and 422
- In-memory store: use a plain dict at module level unless PRD requires a database
- For tests: use 'from httpx import AsyncClient, ASGITransport' and 'async with AsyncClient(transport=ASGITransport(app=app), base_url="http://test") as client:'

Start your response with exactly: # FILE: ${filename}
Then write the complete file. Nothing else.`;

const ollamaBody = JSON.stringify({
  model: 'qwen2.5-coder:32b',
  stream: false,
  options: { temperature: 0.1 },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: `PRD TO IMPLEMENT:\n\n${spec}\n\nGenerate ONLY: ${filename}` }
  ]
});

return [{ json: { ollamaBody, filename, spec } }];

const raw = $input.first().json.message?.content || '';

// Strip markdown fences if model wrapped the output
const cleaned = raw
  .replace(/^```[\w]*\n?/m, '')
  .replace(/\n?```$/m, '')
  .trim();

// Extract filename from # FILE: comment if present
const filenameMatch = cleaned.match(/^# FILE: (.+)/m);
const filename = filenameMatch ? filenameMatch[1].trim() : ($input.first().json.filename || 'unknown.py');

const lines = cleaned.split('\n').length;

return [{ json: { filename, content: cleaned, lines } }];
